  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { ActionPanel } from './components/action_panel/action_panel';
  3→import { Alert } from './components/alert/alert';
  4→import { CommandPalette } from './components/command_palette/command_palette';
  5→import { Detail } from './components/detail/detail';
  6→import { DetailMetadata } from './components/detail/detail_metadata';
  7→import { EmptyState } from './components/empty_state/empty_state';
  8→import {
  9→  Form,
 10→  FormCheckbox,
 11→  FormDatePicker,
 12→  FormDropdown,
 13→  FormTextArea,
 14→  FormTextField,
 15→} from './components/form';
 16→import { Grid, GridItem } from './components/grid';
 17→import { Kbd } from './components/kbd/kbd';
 18→import { List, ListItem, ListSection } from './components/list';
 19→import { SearchBar } from './components/search_bar/search_bar';
 20→import { ToastContainer } from './components/toast/toast_container';
 21→import { MOCK_COLORS, MOCK_SECTIONS } from './data/mock_data';
 22→import { useAlert } from './hooks/use_alert';
 23→import {
 24→  NavigationContextProvider,
 25→  useNavigationStack,
 26→} from './hooks/use_navigation';
 27→import { useToast } from './hooks/use_toast';
 28→import type {
 29→  ColorItemData,
 30→  ListItemData,
 31→  ListItemMetadataEntry,
 32→  SectionData,
 33→} from './types';
 34→
 35→type NavViewData =
 36→  | { type: 'grid' }
 37→  | { type: 'form' }
 38→  | { type: 'detail'; item: ListItemData };
 39→
 40→function filterSections(sections: SectionData[], query: string): SectionData[] {
 41→  if (!query) return sections;
 42→  const lower = query.toLowerCase();
 43→  return sections
 44→    .map(section => ({
 45→      ...section,
 46→      items: section.items.filter(
 47→        item =>
 48→          item.title.toLowerCase().includes(lower) ||
 49→          item.subtitle?.toLowerCase().includes(lower),
 50→      ),
 51→    }))
 52→    .filter(section => section.items.length > 0);
 53→}
 54→
 55→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 56→  if (!query) return colors;
 57→  const lower = query.toLowerCase();
 58→  return colors.filter(
 59→    c =>
 60→      c.title.toLowerCase().includes(lower) ||
 61→      c.subtitle?.toLowerCase().includes(lower),
 62→  );
 63→}
 64→
 65→function flattenItems(sections: SectionData[]): ListItemData[] {
 66→  return sections.flatMap(s => s.items);
 67→}
 68→
 69→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 70→  switch (entry.type) {
 71→    case 'label':
 72→      return (
 73→        <DetailMetadata.Label
 74→          key={index}
 75→          title={entry.title}
 76→          text={entry.text}
 77→        />
 78→      );
 79→    case 'link':
 80→      return (
 81→        <DetailMetadata.Link
 82→          key={index}
 83→          title={entry.title}
 84→          text={entry.text}
 85→          target={entry.target}
 86→        />
 87→      );
 88→    case 'tag-list':
 89→      return (
 90→        <DetailMetadata.TagList key={index} title={entry.title}>
 91→          {entry.tags.map(tag => (
 92→            <DetailMetadata.Tag
 93→              key={tag.text}
 94→              text={tag.text}
 95→              color={tag.color}
 96→            />
 97→          ))}
 98→        </DetailMetadata.TagList>
 99→      );
100→    case 'separator':
101→      return <DetailMetadata.Separator key={index} />;
102→  }
103→}
104→
105→function ColorSwatch({ color }: { color: string }) {
106→  return (
107→    <div
108→      className="grid-item__color-swatch"
109→      style={{ backgroundColor: color }}
110→    />
111→  );
112→}
113→
114→function SearchIcon() {
115→  return (
116→    <svg
117→      width="48"
118→      height="48"
119→      viewBox="0 0 48 48"
120→      fill="none"
121→      xmlns="http://www.w3.org/2000/svg"
122→    >
123→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
124→      <line
125→        x1="30"
126→        y1="30"
127→        x2="42"
128→        y2="42"
129→        stroke="currentColor"
130→        strokeWidth="3"
131→        strokeLinecap="round"
132→      />
133→    </svg>
134→  );
135→}
136→
137→interface SnippetFormState {
138→  name: string;
139→  keyword: string;
140→  snippet: string;
141→  category: string;
142→  isShared: boolean;
143→  expiresAt: string;
144→}
145→
146→const INITIAL_SNIPPET_FORM: SnippetFormState = {
147→  name: '',
148→  keyword: '',
149→  snippet: '',
150→  category: 'general',
151→  isShared: false,
152→  expiresAt: '',
153→};
154→
155→const SNIPPET_CATEGORIES = [
156→  { label: 'General', value: 'general' },
157→  { label: 'Code', value: 'code' },
158→  { label: 'Email', value: 'email' },
159→  { label: 'Template', value: 'template' },
160→];
161→
162→interface CreateSnippetViewProps {
163→  onSubmit: (form: SnippetFormState) => void;
164→}
165→
166→function CreateSnippetView({ onSubmit }: CreateSnippetViewProps) {
167→  const [snippetForm, setSnippetForm] =
168→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
169→  const [formErrors, setFormErrors] = useState<
170→    Partial<Record<keyof SnippetFormState, string>>
171→  >({});
172→
173→  const handleSubmit = useCallback(() => {
174→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
175→    if (!snippetForm.name.trim()) {
176→      errors.name = 'Name is required';
177→    }
178→    if (!snippetForm.snippet.trim()) {
179→      errors.snippet = 'Snippet content is required';
180→    }
181→    setFormErrors(errors);
182→    if (Object.keys(errors).length > 0) {
183→      return;
184→    }
185→    onSubmit(snippetForm);
186→  }, [snippetForm, onSubmit]);
187→
188→  useEffect(() => {
189→    function handleKeyDown(e: KeyboardEvent) {
190→      if (e.key === 'Enter' && e.metaKey) {
191→        e.preventDefault();
192→        handleSubmit();
193→      }
194→    }
195→    window.addEventListener('keydown', handleKeyDown);
196→    return () => window.removeEventListener('keydown', handleKeyDown);
197→  }, [handleSubmit]);
198→
199→  return (
200→    <Form onSubmit={handleSubmit}>
201→      <FormTextField
202→        label="Name"
203→        value={snippetForm.name}
204→        onChange={v => setSnippetForm(prev => ({ ...prev, name: v }))}
205→        placeholder="e.g. Email Signature"
206→        error={formErrors.name}
207→        autoFocus
208→      />
209→      <FormTextField
210→        label="Keyword"
211→        value={snippetForm.keyword}
212→        onChange={v => setSnippetForm(prev => ({ ...prev, keyword: v }))}
213→        placeholder="e.g. !sig"
214→        description="Type this to expand the snippet"
215→      />
216→      <FormDropdown
217→        label="Category"
218→        value={snippetForm.category}
219→        onChange={v => setSnippetForm(prev => ({ ...prev, category: v }))}
220→        options={SNIPPET_CATEGORIES}
221→        placeholder="Select a category"
222→      />
223→      <FormTextArea
224→        label="Snippet"
225→        value={snippetForm.snippet}
226→        onChange={v => setSnippetForm(prev => ({ ...prev, snippet: v }))}
227→        placeholder="Enter your snippet content..."
228→        error={formErrors.snippet}
229→        rows={5}
230→      />
231→      <FormCheckbox
232→        label="Share with team"
233→        checked={snippetForm.isShared}
234→        onChange={v => setSnippetForm(prev => ({ ...prev, isShared: v }))}
235→        description="Make this snippet available to your team members"
236→      />
237→      <FormDatePicker
238→        label="Expires"
239→        value={snippetForm.expiresAt}
240→        onChange={v => setSnippetForm(prev => ({ ...prev, expiresAt: v }))}
241→        description="Optional expiration date"
242→      />
243→    </Form>
244→  );
245→}
