247→export function App() {
248→  const [query, setQuery] = useState('');
249→  const [selectedIndex, setSelectedIndex] = useState(0);
250→  const [actionsOpen, setActionsOpen] = useState(false);
251→  const { toasts, show: showToast, hide: hideToast } = useToast();
252→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
253→  const nav = useNavigationStack<NavViewData>('Raycast');
254→
255→  const viewType = nav.currentEntry?.data.type ?? 'root';
256→
257→  useEffect(() => {
258→    if (nav.stackDepth === 0) {
259→      setQuery('');
260→      setSelectedIndex(0);
261→      setActionsOpen(false);
262→    }
263→  }, [nav.stackDepth]);
264→
265→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
266→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
267→  const filteredColors = useMemo(
268→    () => filterColors(MOCK_COLORS, query),
269→    [query],
270→  );
271→
272→  const selectedItem =
273→    viewType === 'root' ? allItems[selectedIndex] : undefined;
274→
275→  const handleQueryChange = useCallback((value: string) => {
276→    setQuery(value);
277→    setSelectedIndex(0);
278→    setActionsOpen(false);
279→  }, []);
280→
281→  const handleActiveIndexChange = useCallback((index: number) => {
282→    setSelectedIndex(index);
283→    setActionsOpen(false);
284→  }, []);
285→
286→  const handleCopyColor = useCallback(
287→    (color: ColorItemData) => {
288→      showToast({
289→        style: 'info',
290→        title: 'Copied color',
291→        message: color.color,
292→      });
293→    },
294→    [showToast],
295→  );
296→
297→  const handleGridAction = useCallback(
298→    (index: number) => {
299→      const color = filteredColors[index];
300→      if (color) {
301→        handleCopyColor(color);
302→      }
303→    },
304→    [filteredColors, handleCopyColor],
305→  );
306→
307→  const handleSnippetSubmit = useCallback(
308→    (form: SnippetFormState) => {
309→      showToast({
310→        style: 'success',
311→        title: 'Snippet Created',
312→        message: form.name,
313→      });
314→      nav.pop();
315→    },
316→    [showToast, nav],
317→  );
318→
319→  const handleDrillIn = useCallback(() => {
320→    const item = allItems[selectedIndex];
321→    if (!item) return;
322→
323→    setActionsOpen(false);
324→
325→    if (item.id === 'color-picker') {
