327→      setQuery('');
328→      setSelectedIndex(0);
329→      showToast({ style: 'success', title: 'Opened Color Picker' });
330→    } else if (item.detail) {
331→      nav.push(item.title, { type: 'detail', item });
332→      setQuery('');
333→      showToast({ style: 'success', title: `Opened ${item.title}` });
334→    } else {
335→      showToast({ style: 'success', title: `Opened ${item.title}` });
336→    }
337→  }, [allItems, selectedIndex, showToast, nav]);
338→
339→  const handleOpenCreateSnippet = useCallback(() => {
340→    setActionsOpen(false);
341→    nav.push('Create Snippet', { type: 'form' });
342→    setQuery('');
343→    setSelectedIndex(0);
344→  }, [nav]);
345→
346→  const toggleActions = useCallback(() => {
347→    setActionsOpen(prev => !prev);
348→  }, []);
349→
350→  const closeActions = useCallback(() => {
351→    setActionsOpen(false);
352→  }, []);
353→
354→  useEffect(() => {
355→    function handleKeyDown(e: KeyboardEvent) {
356→      if (e.key === 'k' && e.metaKey && viewType !== 'form') {
357→        e.preventDefault();
358→        setActionsOpen(prev => !prev);
