374→    () => [
375→      {
376→        label: 'Open',
377→        shortcut: <Kbd keys={['↵']} />,
378→        onClick: () => {
379→          if (selectedItem) {
380→            showToast({
381→              style: 'success',
382→              title: `Opened ${selectedItem.title}`,
383→            });
