433→                />
434→                <path
435→                  d="M12 13V22M16 13V22M20 13V22M10 10H22M13 10V9C13 8.45 13.45 8 14 8H18C18.55 8 19 8.45 19 9V10"
436→                  stroke="currentColor"
437→                  strokeWidth="1.5"
438→                  strokeLinecap="round"
439→                  strokeLinejoin="round"
440→                />
