472→
473→  const navDirectionClass =
474→    nav.direction === 'push'
475→      ? ' command-palette__nav-view--push'
476→      : nav.direction === 'pop'
477→        ? ' command-palette__nav-view--pop'
478→        : '';
479→
480→  const contextLabel =
481→    nav.breadcrumbs.length > 0
482→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1].label
483→      : 'Raycast';
484→
485→  function renderCurrentView() {
486→    const entry = nav.currentEntry;
487→    if (!entry) return null;
488→
489→    switch (entry.data.type) {
