498→          <Grid
499→            itemCount={filteredColors.length}
500→            columns={4}
501→            onActiveIndexChange={handleActiveIndexChange}
502→            onAction={handleGridAction}
503→          >
504→            {filteredColors.map((color, index) => (
505→              <GridItem
506→                key={color.id}
507→                index={index}
508→                icon={<ColorSwatch color={color.color} />}
509→                title={color.title}
510→                subtitle={color.subtitle}
511→              />
512→            ))}
513→          </Grid>
514→        );
515→      case 'form':
516→        return <CreateSnippetView onSubmit={handleSnippetSubmit} />;
517→      case 'detail': {
518→        const itemDetail = entry.data.item.detail;
519→        if (!itemDetail) return null;
520→        return (
521→          <Detail
522→            markdown={itemDetail.markdown}
523→            metadata={
524→              itemDetail.metadata ? (
525→                <DetailMetadata>
526→                  {itemDetail.metadata.map(renderMetadataEntry)}
527→                </DetailMetadata>
528→              ) : undefined
529→            }
530→          />
531→        );
532→      }
533→    }
534→  }
535→
536→  return (
537→    <NavigationContextProvider value={nav}>
538→      <CommandPalette isLoading>
539→        <SearchBar
540→          value={query}
541→          onChange={handleQueryChange}
542→          activeDescendantId={activeDescendantId}
