549→            key={nav.stackDepth}
550→            className={`command-palette__nav-view${navDirectionClass}`}
551→          >
552→            <div className="command-palette__body">
553→              <div className="command-palette__list-container">
554→                {renderCurrentView()}
555→              </div>
556→            </div>
557→          </div>
558→        ) : (
559→          <div
560→            className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
561→          >
562→            <div className="command-palette__list-container">
563→              {allItems.length === 0 ? (
564→                <EmptyState
565→                  icon={<SearchIcon />}
566→                  title="No Results"
567→                  description="Try a different search term"
568→                />
569→              ) : (
570→                <List
571→                  itemCount={allItems.length}
572→                  onActiveIndexChange={handleActiveIndexChange}
573→                  onAction={handleDrillIn}
574→                >
575→                  {(() => {
576→                    let globalIndex = 0;
577→                    return filtered.map(section => (
578→                      <ListSection key={section.title} title={section.title}>
579→                        {section.items.map(item => {
580→                          const idx = globalIndex++;
581→                          return (
582→                            <ListItem
583→                              key={item.id}
584→                              index={idx}
585→                              title={item.title}
586→                              subtitle={item.subtitle}
587→                              icon={item.icon}
588→                              accessories={item.accessories}
589→                            />
590→                          );
591→                        })}
592→                      </ListSection>
593→                    ));
594→                  })()}
595→                </List>
596→              )}
597→            </div>
598→            {detail && (
599→              <Detail
600→                markdown={detail.markdown}
601→                metadata={
602→                  detail.metadata ? (
603→                    <DetailMetadata>
604→                      {detail.metadata.map(renderMetadataEntry)}
605→                    </DetailMetadata>
606→                  ) : undefined
607→                }
608→              />
609→            )}
610→          </div>
611→        )}
612→        <ActionPanel
613→          contextLabel={contextLabel}
614→          actions={
615→            viewType === 'form'
616→              ? [
617→                  {
618→                    label: 'Submit',
619→                    shortcut: <Kbd keys={['⌘', '↵']} />,
620→                  },
621→                ]
622→              : [
623→                  {
624→                    label: 'Open',
625→                    shortcut: <Kbd keys={['↵']} />,
626→                  },
627→                  {
628→                    label: 'Actions',
629→                    shortcut: <Kbd keys={['⌘', 'K']} />,
630→                    onClick: toggleActions,
631→                  },
632→                ]
633→          }
634→          dropdownOpen={actionsOpen}
635→          dropdownActions={dropdownActions}
636→          onDropdownClose={closeActions}
637→        />
638→        {alertState && (
639→          <Alert
640→            title={alertState.title}
641→            message={alertState.message}
642→            icon={alertState.icon}
643→            primaryAction={alertState.primaryAction}
644→            dismissAction={alertState.dismissAction}
645→            onDismiss={dismissAlert}
646→          />
647→        )}
648→        <ToastContainer toasts={toasts} onDismiss={hideToast} />
649→      </CommandPalette>
650→    </NavigationContextProvider>
651→  );
652→}
