 1→@use '../../styles/tokens' as *;
 2→
 3→.command-palette-overlay {
 4→  position: fixed;
 5→  inset: 0;
 6→  display: flex;
 7→  align-items: flex-start;
 8→  justify-content: center;
 9→  padding-top: 15vh;
10→}
11→
12→.command-palette {
13→  position: relative;
14→  width: $command-palette-width;
15→  max-width: calc(100vw - $space-6 * 2);
16→  max-height: 500px;
17→  display: flex;
18→  flex-direction: column;
19→  background: linear-gradient(
20→    180deg,
21→    rgba($color-background, 0.4) 0%,
22→    rgba($color-surface, 0.4) 100%
23→  );
24→  backdrop-filter: blur(72px) saturate(200%);
25→  -webkit-backdrop-filter: blur(72px) saturate(200%);
26→  border-radius: $radius-window;
27→  border: none;
28→  box-shadow:
29→    $shadow-window,
30→    inset 0 0 0 1px $border-200;
31→  overflow: hidden;
32→  animation: palette-appear $transition-slow ease-out both;
33→}
34→
35→.command-palette__body {
36→  display: flex;
37→  flex: 1;
38→  min-height: 0;
39→  overflow: hidden;
40→  position: relative;
41→}
42→
43→.command-palette__nav-view {
44→  display: flex;
45→  flex: 1;
46→  min-height: 0;
47→  overflow: hidden;
48→  width: 100%;
49→
50→  &--push {
51→    animation: nav-slide-in-left $transition-slow ease-out both;
52→  }
53→
54→  &--pop {
55→    animation: nav-slide-in-right $transition-slow ease-out both;
56→  }
57→}
58→
59→@keyframes nav-slide-in-left {
60→  from {
61→    opacity: 0;
62→    transform: translateX(40px);
63→  }
64→  to {
