@use '../../styles/tokens' as *;

.command-palette-overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding-top: 15vh;
}

.command-palette {
  position: relative;
  width: $command-palette-width;
  max-width: calc(100vw - $space-6 * 2);
  max-height: 500px;
  display: flex;
  flex-direction: column;
  background: linear-gradient(
    180deg,
    rgba($color-background, 0.4) 0%,
    rgba($color-surface, 0.4) 100%
  );
  backdrop-filter: blur(72px) saturate(200%);
  -webkit-backdrop-filter: blur(72px) saturate(200%);
  border-radius: $radius-window;
  border: none;
  box-shadow:
    $shadow-window,
    inset 0 0 0 1px $border-200;
  overflow: hidden;
  animation: palette-appear $transition-slow ease-out both;
}

.command-palette__body {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
  position: relative;
}

.command-palette__nav-view {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
  width: 100%;

  &--push {
    animation: nav-slide-in-left $transition-slow ease-out both;
  }

  &--pop {
    animation: nav-slide-in-right $transition-slow ease-out both;
  }
}

@keyframes nav-slide-in-left {
  from {
    opacity: 0;
    transform: translateX(40px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes nav-slide-in-right {
  from {
    opacity: 0;
    transform: translateX(-40px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.command-palette__list-container {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  overflow: hidden;

  .command-palette__body--has-detail & {
    flex: 0 0 40%;
  }
}

